import{Channel}from"../constants";let counts;export function setCounts(channelCount){counts=channelCount}export function parseChannelString(selector,whitelist){let{type,channel}=selector;const{mixType,mixNumber}=selector;if(counts&&mixType){if(!mixNumber||mixNumber<1){throw new Error("Invalid mix channel provided")}switch(mixType){case"AUX":case"FX":if(!(mixNumber<=counts[mixType]))throw new Error("Invalid mix channel provided");break;default:throw new Error("Invalid mix type provided")}}if(!Object.keys(Channel).includes(type)){throw new Error("Invalid channel type provided")}if(["MAIN","TALKBACK"].includes(type)){channel=1}const oldChannel=channel;channel=Math.trunc(channel);if(!(channel>0)||channel!==oldChannel||counts&&!(counts[type]&&counts[type]>=channel)){throw new Error("Invalid channel provided")}return`${Channel[type]}/ch${channel}`}